#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=2e5+5;
int n,c,a[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>c;
	for(int i=1; i<=n; i++) {
		cin>>a[i];
	}
	sort(a+1,a+1+n);
	int l=1,rr=1,r2=1,ans=0;
	for(int l=1; l<=n; l++) {
		while(rr<=n&&a[rr]-a[l]<=c) {
			rr++;
		}
		while(r2<=n&&a[r2]-a[l]<c) {
			r2++;
		}
		if(a[r2]-a[l]==c&&a[rr-1]-a[l]==c&&rr>=2){
			ans+=rr-r2;
		}
	}
	cout<<ans;
	return 0;
}
